#include <bits/stdc++.h>
#define ll long long int
#define MOD 1000000007
#define pii pair<int,int>
#define iii tuple<int,int,int>
#define FASTIO cin.tie(0),ios_base::sync_with_stdio(0)
using namespace std;

int dp[101][101][4];
int n;
string a;
int arr[101];

int recur(int left, int right, int color){
    if(left==right){
        if(arr[left]==color) return 0;
        return 1;
    }
    int & ret = dp[left][right][color];
    if(ret != -1) return ret;
    ret = 1234567890;
    for(int i=left; i<=right;i++){
        ret = min(ret, recur(left, i, color) + recur(i+1, right, color));
    }
    for(int i=1;i<=3;i++){
        if(i!=color) ret = min(ret, recur(left, right, i) + 1);
    }
    return ret;
}

int main(){
    cin>>n;
    cin>>a;
    for(int i=1;i<=n;i++){
        if(a[i-1] == 'R') arr[i] = 1;
        if(a[i-1] == 'G') arr[i] = 2;
        if(a[i-1] == 'B') arr[i] = 3;
    }
    memset(dp, -1, sizeof dp);
    int ans = min(recur(1,n,1), min(recur(1,n,2),recur(1,n,3)))+1;
    cout<<ans;
}